  ('retired-d0d1b9a2-moex-00460', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關應收回以前年度之預付款項將不再繼續支用，並於年底將其改列為應收款項時，依中央政 府普通公務單位會計制度之一致規定應為之分錄為何？', '["借：資產負債淨額，貸：預付款", "借：其他應收款，貸：預付款", "借：經費賸餘，貸：預付款", "借：繳付公庫數，貸：預付款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00461', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央總會計制度及中央政府普通公務單位會計制度之一致規定，下列關於中央政府長期投資之', '["甲機關投資A公司股權25%，未參與其經營，故以其他長期投資入帳", "乙 機關撥款設置B作業基金，撥充基金之數應以其他長期投資入帳，且期末仍應調整權益", "編製 中央總會計報告時，須編製「公務機關平衡表科目明細表（長期投資）」，表列「採權益法之投資」 不包括特別收入基金", "C國營事業民營化後雖僅持股18%，但其指派董事人選獲選為董事長， 故仍以採權益法之投資列帳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00462', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關有一測量儀器帳面金額200萬元，因已無需要，爰與國外某一研究單位洽商後決定與其交 換另一測量儀器，但甲機關尚須支付10萬元予國外研究單位。甲機關擬換入之儀器帳面金額500 萬元，公允價值為510萬元。下列敘述何者正確？', '["甲機關認列換入財產成本為210萬元，無財產交易利益", "甲機關認列換入財產成本為500萬元，認列財產交易利益290萬元", "甲機關認列換入財產成本為510萬元，認列財產交易利益310萬元", "甲機關認列換入財產成本為510萬元，認列財產交易利益300萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00463', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央公共債務會計制度之規定，下列關於各項債務期間起訖之敘述，何者正確？', '["自實際發行或契約生效之日起，至債務兌付期限屆滿或償清之日止", "自核定發行或契約簽定之日起，至債務兌付期限屆滿或償清之日止", "自核定發行或契約生效之日起，至債務兌付期限屆滿並償清之日止", "自實際發行或契約簽定之日起，至債務兌付期限屆滿並償清之日止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00464', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '中央政府甲機關所設之資本計畫基金，因興建工程所需自籌經費不敷，其中屬非自償部分由甲機 關編列預算撥補，其會計處理應借記？', '["設備及投資支出", "補助特種基金", "購建中固定資產", "增撥非營業特種基金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00465', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，乙機關原有電腦設備 1 部，成本 10 萬元，估計 殘值1萬元，耐用年限3年，107年底已提列折舊3萬元，108年12月31日以3萬元有償移給 地方政府某學校，則該交易將使乙機關之支出科目產生何種變化？', '["淨增4萬元", "淨減3萬元", "淨增2萬元", "淨減1萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00466', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關於108年底各科目之帳載餘額分別為投資 收益300萬元、廢舊物品售價收入10萬元、繳付公庫數450萬元、投資資本收回100萬元、收 入預算數1,000萬元，則該年度之收入類會計科目金額為何？', '["1,860萬元", "1,410萬元", "410萬元", "310萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00467', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依國有財產會計制度之規定，下列會計科目中應設置累計折舊者，計有幾項？①土地改良物', '["租賃資產", "雜項設備", "租賃權益改良", "1項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00468', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '下列財政部所頒布之各項特種公務會計制度，其會計基礎採現金收付基礎者計有幾項？①中央公', '["關稅徵課會計制度", "內地稅徵課會計制度", "國庫出納會計制度  ⑤國 有財產會計制度", "1項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00469', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依政府會計準則公報及中央政府普通公務單位會計制度之一致規定，下列敘述何者正確？①甲', '["乙機關以一儀器設備與民 間企業交換類似設備，雙方無給付價金，故乙機關以換出資產的帳面金額作為換入資產入帳金額， 後續須以換入資產的剩餘使用年限計提折舊", "丙機關收藏供展示用的傳承資產無須計提折舊", "丁機關承租倉庫50年，因租期屆滿得以優惠價格優先承購，屬融資租賃，故以各期租金給付總 額之現值總額較承租該倉庫之租賃開始日之公允價值孰低者，認列租賃資產", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
